custom_css:
[selector='button-align'] div {
  align-content: center;
  text-align: center;
}
[selector="buttons-bar"] button {
    width: 100% !important;
}
[selector="multicolumn-error"] {
    background-color: #f8d7da;      /* same as .alert-danger */
    border: 1px solid #f5c2c7;
    color: #842029;
    border-radius: 0.375rem;
    padding: 12px;
    margin-bottom: 10px;
}
